export function evalStatusCommand(): string {
  return process.env.NEMOCLAW_STATUS ?? 'idle';
}

import { describe, expect, it } from 'vitest';
import { evalStatusCommand } from '../nemoclaw/src/lib/eval-status-command';

describe('evalStatusCommand', () => {
  it('returns idle by default', () => {
    expect(evalStatusCommand()).toBe('idle');
  });
});
